mapper.select:
SELECT id, tenant_id, channel_code, channel_name, channel_type, config_json,
       enabled, created_by, updated_by, created_at, updated_at
  FROM batch.notification_channel
 WHERE tenant_id = #{tenantId}
   AND channel_code = #{channelCode}
   AND is_deleted = false

mapper.update:
UPDATE batch.notification_channel
   SET is_deleted = true,
       updated_at = CURRENT_TIMESTAMP
 WHERE tenant_id = #{tenantId}
   AND channel_code = #{channelCode}
   AND is_deleted = false
